// 線D：把 KEIS 物件編號解析成永慶官網連結（KEIS 欄位裡沒有，只能反查官網搜尋）
// 做法：GET buy.yungching.com.tw/list/{城市}-_c/{編號數字}_kw → 讀 JSON-LD ItemList 拿候選
//       → 逐一開 /house/{id} 用標題驗證（清單第一個候選是固定的假 id，一定要驗）
// 查不到就退回 official_url（houseol），至少 KEIS 那筆還是建得起來。
const ctx = $('取貼文結果').first().json;
const norm = s => String(s || '').replace(/\s+/g, '').toLowerCase();
const digits = String(ctx.contract_no || '').replace(/^[A-Za-z]+/, '');
const city = (String(ctx['地址'] || '').match(/^(.{1,3}?[縣市])/) || [])[1] || '高雄市';
const out = { ycUrl: '', ycHouseId: '', ycResolveNote: '' };
try {
  const listUrl = `https://buy.yungching.com.tw/list/${encodeURIComponent(city)}-_c/${digits}_kw`;
  const html = String(await this.helpers.httpRequest({ url: listUrl, json: false, timeout: 20000,
    headers: { 'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120 Safari/537.36', 'accept-language': 'zh-TW,zh;q=0.9' } }));
  let cands = [];
  for (const m of html.matchAll(/<script type="application\/ld\+json">([\s\S]*?)<\/script>/g)) {
    let d; try { d = JSON.parse(m[1]); } catch (e) { continue; }
    if (d['@type'] === 'ItemList' && Array.isArray(d.itemListElement)) {
      cands = d.itemListElement.map(e => String(e.url || '')).filter(u => /\/house\/\d+/.test(u));
    }
  }
  const want = norm(ctx['案名']).split('|')[0].split('｜')[0];
  for (const u of cands.slice(0, 4)) {
    const page = String(await this.helpers.httpRequest({ url: u, json: false, timeout: 20000,
      headers: { 'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120 Safari/537.36' } }));
    const t = (page.match(/<title>([\s\S]*?)<\/title>/) || [])[1] || '';
    const head = norm(t.split('|')[0].split('｜')[0]);
    if (head && want && (head === want || head.startsWith(want) || want.startsWith(head))) {
      out.ycUrl = u; out.ycHouseId = (u.match(/\/house\/(\d+)/) || [])[1] || ''; out.ycResolveNote = 'ok'; break;
    }
  }
  if (!out.ycUrl) out.ycResolveNote = cands.length ? `候選 ${cands.length} 筆都對不上標題` : '搜尋無候選';
} catch (e) {
  out.ycResolveNote = '查詢失敗：' + (e.message || e);
}
if (!out.ycUrl) out.ycUrl = ctx.official_url || '';
// adcase_road：地址扣掉城市（KEIS 廣告追蹤的路段欄位是「行政區+路名」）
const road = String(ctx['地址'] || '').replace(/^.{1,3}?[縣市]/, '');
return [{ json: { ...ctx, ...out, adcaseRoad: road } }];

// 取 KEIS 新增回來的 adcase_id（失敗不擋流程，只記下原因給 LINE 顯示）
const ctx = $('解析永慶連結').first().json;
const r = $input.first().json || {};
const body = r.body ?? r;
const status = Number(r.statusCode ?? 0);
const adcaseId = body && body.adcase_id ? Number(body.adcase_id) : null;
let note;
if (adcaseId) note = ctx.ycResolveNote === 'ok' ? '已同步' : `已同步（連結用備援：${ctx.ycResolveNote}）`;
else note = `建立失敗（HTTP ${status}）${typeof body === 'object' ? ' ' + JSON.stringify(body).slice(0, 200) : ''}`;
return [{ json: { ...ctx, keisAdcaseId: adcaseId, keisNote: note } }];
